const config = $('Workflow Config').item.json;
const uploadId = config.upload_id;
const userId = config.user_id;
const purpose = config.purpose || 'timetable';
const timezone = config.timezone || 'Asia/Kuala_Lumpur';
const mimeType = config.mime_type || 'image/png';
const model = config.gemini_model || 'gemini-2.0-flash';

// Extract Gemini response - handle ALL output shapes:
// Simplify ON:  $json.content = 'raw text string'
// Simplify OFF: $json.content = { parts: [{ text: 'raw text' }] }
// Text node:    $json.response or $json.text = 'raw text'
let geminiResponse = '';
if (typeof $json.content === 'string') {
  geminiResponse = $json.content;
} else if ($json.content && $json.content.parts && Array.isArray($json.content.parts)) {
  geminiResponse = ($json.content.parts[0] && $json.content.parts[0].text) || '';
} else if (typeof $json.response === 'string') {
  geminiResponse = $json.response;
} else if (typeof $json.text === 'string') {
  geminiResponse = $json.text;
} else if ($json.output && typeof $json.output === 'string') {
  geminiResponse = $json.output;
}

// Determine extraction method for metadata
const extractedFrom = mimeType === 'application/pdf'
  ? (geminiResponse.length > 0 && $json.inputType !== 'binary' ? 'gemini_text_pdf' : 'gemini_vision_pdf')
  : 'gemini_vision_image';

// Parse JSON with repair fallback
let items = [];
let parseWarnings = [];

try {
  const parsed = JSON.parse(geminiResponse);
  items = Array.isArray(parsed) ? parsed : [];
} catch (e) {
  parseWarnings.push('initial_parse_failed');
  const match = geminiResponse.match(/\[[\s\S]*\]/);
  if (match) {
    try {
      items = JSON.parse(match[0]);
    } catch (e2) {
      parseWarnings.push('json_extraction_failed');
      items = [];
    }
  }
}

// Normalization helpers
const validDays = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
const dayMap = {
  'Monday':'Mon','Tuesday':'Tue','Wednesday':'Wed','Thursday':'Thu',
  'Friday':'Fri','Saturday':'Sat','Sunday':'Sun',
  'Mon':'Mon','Tue':'Tue','Wed':'Wed','Thu':'Thu',
  'Fri':'Fri','Sat':'Sat','Sun':'Sun',
  'Tues':'Tue','Thurs':'Thu','Thur':'Thu'
};

function normalizeTime(t) {
  if (!t) return null;
  t = String(t).trim().toLowerCase();
  let isPM = /pm/.test(t);
  let isAM = /am/.test(t);
  t = t.replace(/[ap]m/g, '').trim();
  if (/^\d{3,4}$/.test(t)) {
    const p = t.padStart(4,'0');
    t = p.slice(0,2) + ':' + p.slice(2);
  } else if (/^\d{1,2}[.:]\d{2}$/.test(t)) {
    const parts = t.replace('.',':').split(':');
    t = parts[0].padStart(2,'0') + ':' + parts[1];
  } else if (/^\d{1,2}$/.test(t)) {
    t = t.padStart(2,'0') + ':00';
  } else {
    return null;
  }
  if (isPM || isAM) {
    const parts = t.split(':');
    let hour = parseInt(parts[0]);
    if (isPM && hour < 12) hour += 12;
    if (isAM && hour === 12) hour = 0;
    t = hour.toString().padStart(2,'0') + ':' + parts[1];
  }
  return t;
}

function timeToMins(t) {
  const p = t.split(':');
  return parseInt(p[0]) * 60 + parseInt(p[1]);
}

function addHour(t) {
  const m = timeToMins(t) + 60;
  const h = Math.floor(m / 60) % 24;
  return h.toString().padStart(2,'0') + ':' + (m % 60).toString().padStart(2,'0');
}

const processedItems = [];
const seen = new Set();

items.forEach(function(item) {
  if (!item || !item.day || !item.start || !item.title) return;

  let day = String(item.day).trim();
  if (dayMap[day]) {
    day = dayMap[day];
  } else if (day.length >= 3) {
    const short = day.charAt(0).toUpperCase() + day.slice(1,3).toLowerCase();
    day = dayMap[short] || short;
  }
  if (!validDays.includes(day)) {
    parseWarnings.push('invalid_day:' + item.day);
    return;
  }

  const start = normalizeTime(item.start);
  let end = normalizeTime(item.end);
  if (!start) { parseWarnings.push('invalid_start'); return; }
  if (!end) end = addHour(start);
  if (timeToMins(end) <= timeToMins(start)) { end = addHour(start); }

  const title = String(item.title || 'Class').trim();
  const location = String(item.location || '').trim();

  const key = day + '|' + start + '|' + title;
  if (seen.has(key)) return;
  seen.add(key);

  processedItems.push({ day, start, end, title, location });
});

if (processedItems.length === 0) parseWarnings.push('no_items_parsed');

return [{
  json: {
    upload_id: uploadId,
    user_id: userId,
    purpose: purpose,
    timezone: timezone,
    items: processedItems,
    meta: {
      source_mime_type: mimeType,
      extracted_from: extractedFrom,
      model_used: model,
      parsed_count: processedItems.length,
      warnings: parseWarnings.slice(0, 5)
    }
  }
}];
